import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Create a fixed size buffer
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Copy the user input into the buffer with bounds checking
        for (int i = 0; i < input.length() && i < bufferSize; i++) {
            buffer[i] = input.charAt(i);
        }

        // Ensure that the buffer is null-terminated to avoid printing garbage characters
        if (input.length() >= bufferSize) {
            buffer[bufferSize - 1] = '\0';
        }

        // Print out a safe version of the user's input from the buffer
        System.out.println("Hello, " + new String(buffer).trim());
    }
}

